const email = $input.first().json;
const from = email.from || 'unknown';
const subject = email.subject || '(no subject)';
const messageId = email.id;
const body = email.textPlain || email.snippet || '(no body)';
const receivedAt = email.date || new Date().toISOString();

const userMessage = `New email received.

From: ${from}
Subject: ${subject}
Message-ID: ${messageId}
Received: ${receivedAt}

--- Body ---
${body.substring(0, 3000)}
--- End ---

Please categorize this email and decide the appropriate action. Your options are:
- Reply: If it needs a response
- Mark as Read: If it's informational only
- Delete: If it's spam
- Draft: If it needs a sensitive or complex reply (save draft, notify on Telegram)
- Ignore: If no action needed`;

return [{ json: { userMessage, from, subject, messageId, receivedAt, rawSnippet: email.snippet } }];

let input; try { input = JSON.parse(query); } catch(e) { input = { notes: query }; }
const body = {
  from_address: input.from || 'unknown',
  subject: input.subject || 'unknown',
  message_id: input.messageId || 'unknown',
  action_taken: input.action || 'unknown',
  notes: input.notes || '',
  processed_at: new Date().toISOString()
};
await helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/email_log',
  headers: { 'apikey': $env.SUPABASE_SERVICE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
  body: JSON.stringify(body)
});
return JSON.stringify({ success: true, logged: body });
